const headers = $input.first().json.headers;
const query = $input.first().json.query;
const token = headers.authorization || '';

if (token !== `Bearer ${$env.API_BEARER_TOKEN}`) {
  throw new Error('401 Unauthorized: Invalid Bearer Token');
}

const userId = headers['x-user-id'] || '11111111-1111-1111-1111-111111111111';
const limit = query.limit ? parseInt(query.limit) : 20;
const offset = query.offset ? parseInt(query.offset) : 0;
const filter = query.filter || 'ALL'; // ALL, HIGH_PRIORITY

return [{ json: { user_id: userId, limit, offset, filter } }];

const items = $input.all();
return [{
  json: {
    status: 'success',
    count: items.length,
    data: items.map(i => i.json)
  }
}];
